import{c as t,Q as s,j as i,m as a}from"./chunks/framework.C5e1CAgN.js";const o="/_pr/417/assets/2026-05-11-mattpocock-skills-cover.DrKpV6LY.webp",g=JSON.parse('{"title":"69,816 Stars, Four Hidden Skills","description":"","frontmatter":{},"headers":[],"relativePath":"case-studies/2026-05-11-mattpocock-skills.md","filePath":"case-studies/2026-05-11-mattpocock-skills.md","lastUpdated":null}'),r={name:"case-studies/2026-05-11-mattpocock-skills.md"};function n(d,e,l,h,c,p){return s(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="_69-816-stars-four-hidden-skills" tabindex="-1">69,816 Stars, Four Hidden Skills <a class="header-anchor" href="#_69-816-stars-four-hidden-skills" aria-label="Permalink to &quot;69,816 Stars, Four Hidden Skills&quot;">​</a></h1><p><img src="'+o+`" alt="Cover"></p><blockquote><p><strong>Disclosure</strong>: Written from NLPM audit data on 2026-05-11 and re-verified against the live state of <code>mattpocock/skills</code> the same day. The repository&#39;s plugin manifest and the affected <code>SKILL.md</code> files were inspected directly via <code>git ls-tree</code> and <code>gh api</code>; star and fork counts come from <code>GET /repos/mattpocock/skills</code> at audit time. Cover image generated with OpenAI <code>gpt-image-1</code> (gpt-image-2 was requested but requires org verification not enabled on this account).</p></blockquote><hr><h2 id="the-project" tabindex="-1">The Project <a class="header-anchor" href="#the-project" aria-label="Permalink to &quot;The Project&quot;">​</a></h2><p><a href="https://github.com/mattpocock/skills" target="_blank" rel="noreferrer"><code>mattpocock/skills</code></a> is Matt Pocock&#39;s personal Claude Code skill kit, published 2026-02-03 with the tagline <em>&quot;Skills for Real Engineers. Straight from my .claude directory.&quot;</em> Three months later it carries <strong>69,816 stars and 6,039 forks</strong> — by raw popularity the most prominent skill kit on GitHub outside Anthropic&#39;s own examples. Matt is one of the most-followed TypeScript educators in the ecosystem; the repository&#39;s reach is amplified by his Twitter/YouTube footprint.</p><p>The repository&#39;s purpose is to package his daily TS/engineering workflow as installable Claude Code skills covering TDD, code review, refactoring, prototyping, triage, and writing. Users discover it through Matt&#39;s social channels and run <code>claude plugin install</code> against it.</p><hr><h2 id="the-audit" tabindex="-1">The Audit <a class="header-anchor" href="#the-audit" aria-label="Permalink to &quot;The Audit&quot;">​</a></h2><p><strong>Date</strong>: 2026-05-11 | <strong>Artifacts scored</strong>: 30 | <strong>NL Score</strong>: <strong>98/100</strong> | <strong>Security</strong>: CLEAR</p><p>The skill kit is, in nearly every respect, exemplary. Twenty-six of the thirty scored artifacts landed between 96 and 100. The two scripts in <code>skills/misc/git-guardrails-claude-code/scripts/</code> and <code>skills/engineering/diagnose/scripts/</code> passed security scrutiny — no eval, no curl-pipe-sh, no credential exfil. The bundled scripts include a guard against creating symlinks into the repo (<code>scripts/link-skills.sh</code>), which is good defensive design. The CLAUDE.md is terse and accurate. The frontmatter on every <code>SKILL.md</code> is valid.</p><p>If the score were the only signal, the audit would close with &quot;well-built; minor <code>relevant</code> vague-quantifier hits on 14 lines.&quot; That&#39;s not the audit&#39;s interesting finding.</p><p>The interesting finding is that <strong>four of the skills users see on the README are not in the manifest</strong>.</p><hr><h2 id="the-bug" tabindex="-1">The Bug <a class="header-anchor" href="#the-bug" aria-label="Permalink to &quot;The Bug&quot;">​</a></h2><p>The repository&#39;s <code>.claude-plugin/plugin.json</code> enumerates skills via an explicit <code>skills:</code> array (not the directory-wildcard form). At audit time it listed 26 skills. The disk had 30 <code>SKILL.md</code> files. The diff:</p><table tabindex="0"><thead><tr><th>Disk path</th><th>Featured in README?</th><th>In <code>plugin.json</code>?</th></tr></thead><tbody><tr><td><code>skills/misc/git-guardrails-claude-code/SKILL.md</code></td><td>Yes (line 172)</td><td><strong>No</strong></td></tr><tr><td><code>skills/misc/setup-pre-commit/SKILL.md</code></td><td>Yes (line 173)</td><td><strong>No</strong></td></tr><tr><td><code>skills/misc/migrate-to-shoehorn/SKILL.md</code></td><td>Yes (line 174)</td><td><strong>No</strong></td></tr><tr><td><code>skills/misc/scaffold-exercises/SKILL.md</code></td><td>Yes (line 175)</td><td><strong>No</strong></td></tr></tbody></table><p>All four files are present on disk with valid <code>name:</code> and <code>description:</code> frontmatter. All four are listed and described in the top-level <code>README.md</code> and again in <code>skills/misc/README.md</code>. They are intended to be public, active skills. They are simply absent from the manifest array.</p><p>When a user runs <code>claude plugin install mattpocock-skills</code>, the runtime reads the manifest, sees 26 skill paths, and registers those. The four <code>misc/</code> skills exist on disk but are invisible to the loader. The user, looking at the README that advertised them, has no signal that anything is missing — <code>claude plugin install</code> succeeds, no warning emitted.</p><p>The audit&#39;s other 16 findings are mechanical: vague-quantifier hits on the word &quot;relevant&quot; across 14 sub-agent prompts, plus two truncated <code>## Output</code> sections. None are user-visible runtime bugs. The four missing manifest entries are.</p><hr><h2 id="the-self-mandate" tabindex="-1">The Self-Mandate <a class="header-anchor" href="#the-self-mandate" aria-label="Permalink to &quot;The Self-Mandate&quot;">​</a></h2><p>The audit&#39;s most striking finding sits not in the score but in the cross-component check.</p><p><code>CLAUDE.md</code> in the same repository contains this rule, verbatim:</p><blockquote><p><em>&quot;Every skill in <code>engineering/</code>, <code>productivity/</code>, or <code>misc/</code> must have…an entry in <code>.claude-plugin/plugin.json</code>.&quot;</em></p></blockquote><p>The maintainer&#39;s own contributing guide mandates the exact check the manifest fails. The other category prefixes — <code>skills/in-progress/</code>, <code>skills/personal/</code>, <code>skills/deprecated/</code> — are correctly absent from the manifest, consistent with their names. Only the <code>misc/</code> group violates the self-imposed rule.</p><p>The bug is not philosophical disagreement with the rule. It&#39;s that the rule isn&#39;t automated. The author wrote it, then drifted from it as the kit grew.</p><hr><h2 id="why-the-other-validators-don-t-catch-it" tabindex="-1">Why The Other Validators Don&#39;t Catch It <a class="header-anchor" href="#why-the-other-validators-don-t-catch-it" aria-label="Permalink to &quot;Why The Other Validators Don&#39;t Catch It&quot;">​</a></h2><p>Eight other validators are in active development for Claude Code plugins, including Anthropic&#39;s own <a href="https://github.com/anthropics/claude-code/blob/main/plugins/plugin-dev/agents/plugin-validator.md" target="_blank" rel="noreferrer"><code>plugin-validator</code></a> agent and the <a href="https://github.com/agentskills/agentskills" target="_blank" rel="noreferrer">Linux Foundation&#39;s <code>skills-ref</code></a> reference library. Running any of them against <code>mattpocock/skills</code> produces a clean report.</p><table tabindex="0"><thead><tr><th>Validator</th><th>What it checks</th><th>Catches this bug?</th></tr></thead><tbody><tr><td><code>claude plugin validate</code> (Anthropic CLI)</td><td>Manifest JSON syntax</td><td>No</td></tr><tr><td><code>plugin-validator</code> (Anthropic agent)</td><td>Per-component frontmatter; manifest field shapes; MCP security</td><td><strong>No</strong> — explicitly outside its documented scope</td></tr><tr><td><code>agentskills</code> / <code>skills-ref</code> (Linux Foundation)</td><td>Per-<code>SKILL.md</code> frontmatter and naming</td><td>No — operates at the skill boundary, not the plugin boundary</td></tr><tr><td>Six third-party linters</td><td>Various per-file checks</td><td>No</td></tr><tr><td><strong>NLPM <code>/nlpm:check</code> and <code>bin/nlpm-check</code></strong></td><td>Manifest array vs. disk enumeration</td><td><strong>Yes</strong> — the diff is mechanical</td></tr></tbody></table><p>The full ecosystem comparison and reasoning is in <a href="./../analysis/ecosystem-gap"><code>analysis/ecosystem-gap.md</code></a>. The short version: every validator concentrates at the single-artifact boundary because per-file linters are easier to ship; the cross-artifact diff requires reading two enumerations at once. The bug class survives because the gate doesn&#39;t exist in any tool the maintainer has reached for.</p><hr><h2 id="the-submission-problem" tabindex="-1">The Submission Problem <a class="header-anchor" href="#the-submission-problem" aria-label="Permalink to &quot;The Submission Problem&quot;">​</a></h2><p>The audit reproduced the finding locally and prepared a fork + branch + push to <code>xiaolai/skills-1</code> for a pull request. GitHub returned the GraphQL response:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>xiaolai does not have the correct permissions to execute CreatePullRequest</span></span></code></pre></div><p>The fork existed, the branch was pushed, the token had the right scopes. The repository&#39;s collaboration policy simply does not permit external PRs. Running <code>gh pr list --repo mattpocock/skills</code> confirms it:</p><table tabindex="0"><thead><tr><th>State</th><th style="text-align:right;">Count</th></tr></thead><tbody><tr><td>Merged</td><td style="text-align:right;"><strong>1</strong> (PR #90, authored by <code>mattpocock</code> himself, 2026-04-28)</td></tr><tr><td>Closed unmerged</td><td style="text-align:right;"><strong>41</strong></td></tr><tr><td>Open</td><td style="text-align:right;"><strong>0</strong></td></tr></tbody></table><p>No external pull request has ever merged in the repository&#39;s three-month history. Forty-one have been opened and closed without merging. The single merged PR is the owner&#39;s own — a self-PR to rename the <code>setup-matt-pocock-skills</code> skill and migrate others to &quot;vague prose.&quot;</p><p>The repository accepts issues, however. External contributor <code>vltansky</code> filed issue #163 the day before this audit (2026-05-10) and Matt has historically engaged with issues. The audit&#39;s findings were filed as <strong><a href="https://github.com/mattpocock/skills/issues/164" target="_blank" rel="noreferrer">issue #164</a></strong> instead, following the maintainer&#39;s evident preference. The issue body included the exact <code>diff</code> invocation that reproduces the four missing entries.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">diff</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &lt;(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">jq</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -r</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;.skills[]&#39; .claude-plugin/plugin.json </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sort</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">)</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">     &lt;(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">find</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> skills </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">-path</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;skills/*/*/SKILL.md&#39; </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">-type</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> f </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sed</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;s|/SKILL.md||;s|^|./|&#39; </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> sort</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">)</span></span></code></pre></div><p>As of the audit date, the issue is open with no maintainer response.</p><hr><h2 id="the-tension" tabindex="-1">The Tension <a class="header-anchor" href="#the-tension" aria-label="Permalink to &quot;The Tension&quot;">​</a></h2><p>The repository contains, in this order:</p><ol><li>A <code>CLAUDE.md</code> mandating that every <code>misc/</code> skill be registered in the manifest.</li><li>A <code>README.md</code> featuring four <code>misc/</code> skills as live, supported entries.</li><li>A <code>plugin.json</code> that omits all four.</li><li>A history of 41 closed external PRs, no merges.</li></ol><p>The user-visible effect: someone reads Matt&#39;s README, runs <code>claude plugin install mattpocock-skills</code>, and gets a kit missing four of the skills they came for. They will not know which four. The kit&#39;s <code>claude plugin install</code> exit code is zero. The official Anthropic validator&#39;s exit code is also zero. The README they came in through still advertises the missing skills as installed.</p><p>For the audit pipeline, the case is a sharp instance of the ecosystem gap NLPM has documented across five high-profile repos (<code>graphify</code>, <code>kubesphere</code>, <code>tanweai</code>, <code>agent-sh</code>, and now <code>mattpocock</code>): authors with deep domain knowledge ship manifest-vs-disk inconsistencies because no tool in their toolchain checks for them, and the bug class is invisible to the developer-time loop (&quot;works on my machine, because my <code>.claude/</code> walks the filesystem&quot;).</p><p>The case for the manifest-vs-disk check existing in canonical form is not theoretical. The most-starred skill kit on GitHub demonstrates it directly.</p><hr><h2 id="what-nlpm-did-and-didn-t" tabindex="-1">What NLPM Did, And Didn&#39;t <a class="header-anchor" href="#what-nlpm-did-and-didn-t" aria-label="Permalink to &quot;What NLPM Did, And Didn&#39;t&quot;">​</a></h2><p>NLPM produced the finding. The audit report and per-finding sidecar are committed at <a href="./../auditor/audits/mattpocock-skills"><code>auditor/audits/mattpocock-skills.md</code></a>. The finding was filed as <a href="https://github.com/mattpocock/skills/issues/164" target="_blank" rel="noreferrer">issue #164</a>. The issue&#39;s outcome depends on Matt; the audit pipeline tracks it for downstream learning.</p><p>NLPM did <strong>not</strong> open a pull request. The earlier memory entry implied &quot;0 PRs in history&quot; — imprecise. The actual count is 1 self-merge and 41 closed external PRs. Either way, the implicit policy is unambiguous: no external code lands.</p><p>NLPM also did not add <code>mattpocock/*</code> to the <code>DENY_OWNERS</code> list. The pattern is a per-repository policy, not org-wide. If a second mattpocock repository surfaces in the discovery pipeline and exhibits the same shape, the evidence will be re-evaluated. Until then, the gate is &quot;verify external-merge history before attempting a PR&quot; — encoded as a one-line <code>gh pr list</code> check in the contributing memory.</p><p>The case study you are reading is the third place this finding will surface: the per-repo audit report (private, in <code>auditor/audits/</code>), the upstream issue (public, awaiting maintainer response), and this article (public, evidence for the rule&#39;s existence).</p><hr><h2 id="the-broader-argument" tabindex="-1">The Broader Argument <a class="header-anchor" href="#the-broader-argument" aria-label="Permalink to &quot;The Broader Argument&quot;">​</a></h2><p><code>mattpocock/skills</code> is a near-perfect skill kit by every test except one. The author is an experienced TypeScript educator, the security surface is clean, the frontmatter is valid, the descriptions are well-written. The bug that survives is not a quality problem. It is an ecosystem problem: the layer at which the bug sits has no validator in canonical form, and the layer the validators do cover — per-file frontmatter, per-script security — was passed cleanly.</p><p>The 69,816 stars are evidence of the author&#39;s craft and reach. They are not evidence that the kit installs as advertised. The single check that would have surfaced the discrepancy — comparing the manifest&#39;s <code>skills:</code> array against <code>find skills -name SKILL.md</code> — exists in no validator the author has reason to reach for. NLPM ships it. After v0.8.0, ships it as a standalone Python script with no Claude Code dependency, designed for the pre-commit and CI loops the author has but hasn&#39;t yet wired up.</p><p>The bug, in a repository this prominent, is not embarrassing for the author. It is informative for the ecosystem.</p><hr><h2 id="links" tabindex="-1">Links <a class="header-anchor" href="#links" aria-label="Permalink to &quot;Links&quot;">​</a></h2><ul><li>Audit report: <a href="./../auditor/audits/mattpocock-skills"><code>auditor/audits/mattpocock-skills.md</code></a></li><li>Upstream issue: <a href="https://github.com/mattpocock/skills/issues/164" target="_blank" rel="noreferrer">mattpocock/skills#164</a></li><li>Ecosystem-gap research: <a href="./../analysis/ecosystem-gap"><code>analysis/ecosystem-gap.md</code></a></li><li>Standalone validator that catches this class: <a href="./../bin/nlpm-check"><code>bin/nlpm-check</code></a> (shipped in NLPM v0.8.0)</li></ul>`,63)])])}const m=t(r,[["render",n]]);export{g as __pageData,m as default};
